int search(int arr[], int size, int target) {
    for (int i = 0; i < size; i++) {
        if (arr[i] == target) {
            return i;
        }
    }
    return -1;
}

int index = search(arr, 5, 99);
if (index != -1) {
    printf("Found at index %d", index);
} else {
    printf("Not found");
}
